            <div class="relative" x-data="{ open: false }">
                <button @click="open = !open"
                    class="account-hover flex items-center gap-3 px-3 py-2 rounded transition-colors">
                    <div class="w-10 h-10 bg-[#F5F5F5] flex items-center justify-center">
                        <span class="text-base text-[#1A1A1A]">{{ substr($user->name, 0, 1) }}</span>
                    </div>
                    <span class="text-base text-[#1A1A1A] hidden md:inline">{{ $user->name }}</span>
                    <svg class="w-5 h-5 text-[#6B6B6B] transition-transform duration-200"
                        :class="{ 'rotate-180': open }" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M19 9l-7 7-7-7" />
                    </svg>
                </button>
                <div x-show="open" x-cloak x-transition @click.away="open = false"
                    class="absolute right-0 mt-3 w-64 bg-white border border-[#E8E8E8] shadow-lg z-50">
                    <div class="p-4 border-b border-[#E8E8E8]">
                        <p class="text-sm font-medium text-[#1A1A1A]">{{ $user->name }}</p>
                        <p class="text-xs text-[#6B6B6B] mt-1">{{ $user->email }}</p>
                    </div>
                    <button wire:click='logout'
                        class="w-full text-left px-4 py-3 text-sm text-[#8B0000] hover:bg-[#F5F5F5] flex items-center gap-2">
                        <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5"
                                d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
                        </svg>
                        Выйти
                    </button>
                </div>
            </div>

            <style>
                .account-hover:hover {
                    background-color: #EEEEEE !important;
                }

                [x-cloak] {
                    display: none !important;
                }
            </style>
        </div>
    </div>
</div>
